    echo >&2
    echo "Error: usage CLI not found. This is required for completions to work in x-set-php-aliases." >&2
    echo "See https://usage.jdx.dev for more information." >&2
    return 1
  fi

  local cur prev words cword was_split comp_args
  _comp_initialize -n : -- "$@" || return
  local spec_file="${TMPDIR:-/tmp}/usage__usage_spec_x_set_php_aliases.spec"
  cat >| "$spec_file" << '__USAGE_EOF__'
name x-set-php-aliases
bin x-set-php-aliases
about "Cache PHP installations and generate shell aliases"
flag --prefix help="Show Homebrew prefix"
__USAGE_EOF__
  # shellcheck disable=SC2207
  _comp_compgen -- -W "$(command usage complete-word --shell bash -f "$spec_file" --cword="$cword" -- "${words[@]}")"
  _comp_ltrim_colon_completions "$cur"
  # shellcheck disable=SC2181
  if [[ $? -ne 0 ]]; then
    unset COMPREPLY
  fi
  return 0
}

if [[ "${BASH_VERSINFO[0]}" -eq 4 && "${BASH_VERSINFO[1]}" -ge 4 || "${BASH_VERSINFO[0]}" -gt 4 ]]; then
  shopt -u hostcomplete && complete -o nospace -o bashdefault -o nosort -F _x_set_php_aliases x-set-php-aliases
else
  shopt -u hostcomplete && complete -o nospace -o bashdefault -F _x_set_php_aliases x-set-php-aliases
fi
